// ─── Resampling engine (same as what runtime would use, but runs at build time)

type Point = [number, number];

const STEPS = 8;

function cubicAt(p0: number, p1: number, p2: number, p3: number, t: number) {
    const mt = 1 - t;
    return (
        mt * mt * mt * p0 +
        3 * mt * mt * t * p1 +
        3 * mt * t * t * p2 +
        t * t * t * p3
    );
}
function quadAt(p0: number, p1: number, p2: number, t: number) {
    const mt = 1 - t;
    return mt * mt * p0 + 2 * mt * t * p1 + t * t * p2;
}

function pathToPolyline(raw: string, sx: number, sy: number): Point[] {
    const d = raw
        .replace(/-?\d*\.?\d+e[-+]?\d+/gi, "0")
        .replace(/\s+/g, " ")
        .trim();
    const tokens =
        d.match(/[MmLlHhVvCcSsQqTtAaZz]|[-+]?[0-9]*\.?[0-9]+/g) ?? [];
    const pts: Point[] = [];
    let cx = 0,
        cy = 0,
        startX = 0,
        startY = 0,
        lctx = 0,
        lcty = 0,
        i = 0;
    const n = () => parseFloat(tokens[i++]);
    const put = (x: number, y: number) => pts.push([x * sx, y * sy]);
    const cubic = (
        x1: number,
        y1: number,
        cx1: number,
        cy1: number,
        cx2: number,
        cy2: number,
        x2: number,
        y2: number,
    ) => {
        for (let s = 1; s <= STEPS; s++) {
            const t = s / STEPS;
            put(cubicAt(x1, cx1, cx2, x2, t), cubicAt(y1, cy1, cy2, y2, t));
        }
    };
    const quad = (
        x1: number,
        y1: number,
        qx: number,
        qy: number,
        x2: number,
        y2: number,
    ) => {
        for (let s = 1; s <= STEPS; s++) {
            const t = s / STEPS;
            put(quadAt(x1, qx, x2, t), quadAt(y1, qy, y2, t));
        }
    };
    while (i < tokens.length) {
        const isCmd = /[A-Za-z]/.test(tokens[i]);
        const c = isCmd ? tokens[i++] : tokens[i];
        switch (c) {
            case "M":
                cx = n();
                cy = n();
                startX = cx;
                startY = cy;
                put(cx, cy);
                break;
            case "m":
                cx += n();
                cy += n();
                startX = cx;
                startY = cy;
                put(cx, cy);
                break;
            case "L":
                cx = n();
                cy = n();
                put(cx, cy);
                break;
            case "l":
                cx += n();
                cy += n();
                put(cx, cy);
                break;
            case "H":
                cx = n();
                put(cx, cy);
                break;
            case "h":
                cx += n();
                put(cx, cy);
                break;
            case "V":
                cy = n();
                put(cx, cy);
                break;
            case "v":
                cy += n();
                put(cx, cy);
                break;
            case "C": {
                const x1 = cx,
                    y1 = cy,
                    cx1 = n(),
                    cy1 = n(),
                    cx2 = n(),
                    cy2 = n(),
                    x2 = n(),
                    y2 = n();
                cubic(x1, y1, cx1, cy1, cx2, cy2, x2, y2);
                lctx = cx2;
                lcty = cy2;
                cx = x2;
                cy = y2;
                break;
            }
            case "c": {
                const x1 = cx,
                    y1 = cy,
                    cx1 = cx + n(),
                    cy1 = cy + n(),
                    cx2 = cx + n(),
                    cy2 = cy + n(),
                    x2 = cx + n(),
                    y2 = cy + n();
                cubic(x1, y1, cx1, cy1, cx2, cy2, x2, y2);
                lctx = cx2;
                lcty = cy2;
                cx = x2;
                cy = y2;
                break;
            }
            case "S": {
                const rx = 2 * cx - lctx,
                    ry = 2 * cy - lcty,
                    cx2 = n(),
                    cy2 = n(),
                    x2 = n(),
                    y2 = n();
                cubic(cx, cy, rx, ry, cx2, cy2, x2, y2);
                lctx = cx2;
                lcty = cy2;
                cx = x2;
                cy = y2;
                break;
            }
            case "s": {
                const rx = 2 * cx - lctx,
                    ry = 2 * cy - lcty,
                    cx2 = cx + n(),
                    cy2 = cy + n(),
                    x2 = cx + n(),
                    y2 = cy + n();
                cubic(cx, cy, rx, ry, cx2, cy2, x2, y2);
                lctx = cx2;
                lcty = cy2;
                cx = x2;
                cy = y2;
                break;
            }
            case "Q": {
                const x1 = cx,
                    y1 = cy,
                    qx = n(),
                    qy = n(),
                    x2 = n(),
                    y2 = n();
                quad(x1, y1, qx, qy, x2, y2);
                lctx = qx;
                lcty = qy;
                cx = x2;
                cy = y2;
                break;
            }
            case "q": {
                const x1 = cx,
                    y1 = cy,
                    qx = cx + n(),
                    qy = cy + n(),
                    x2 = cx + n(),
                    y2 = cy + n();
                quad(x1, y1, qx, qy, x2, y2);
                lctx = qx;
                lcty = qy;
                cx = x2;
                cy = y2;
                break;
            }
            case "A":
            case "a": {
                n();
                n();
                n();
                n();
                n();
                const ex = c === "a" ? cx + n() : n(),
                    ey = c === "a" ? cy + n() : n();
                for (let s = 1; s <= STEPS; s++) {
                    const t = s / STEPS;
                    put(cx + (ex - cx) * t, cy + (ey - cy) * t);
                }
                cx = ex;
                cy = ey;
                break;
            }
            case "Z":
            case "z":
                put(startX, startY);
                cx = startX;
                cy = startY;
                break;
        }
    }
    return pts;
}

function resample(pts: Point[], n: number): Point[] {
    if (pts.length < 2)
        return Array.from({ length: n }, () => pts[0] ?? ([0, 0] as Point));
    const lens: number[] = [0];
    for (let k = 1; k < pts.length; k++) {
        const dx = pts[k][0] - pts[k - 1][0],
            dy = pts[k][1] - pts[k - 1][1];
        lens.push(lens[k - 1] + Math.sqrt(dx * dx + dy * dy));
    }
    const total = lens[lens.length - 1];
    const out: Point[] = [];
    let seg = 0;
    for (let k = 0; k < n; k++) {
        const target = (k / (n - 1)) * total;
        while (seg < lens.length - 2 && lens[seg + 1] < target) seg++;
        const span = lens[seg + 1] - lens[seg];
        const t = span < 1e-10 ? 0 : (target - lens[seg]) / span;
        out.push([
            pts[seg][0] + (pts[seg + 1][0] - pts[seg][0]) * t,
            pts[seg][1] + (pts[seg + 1][1] - pts[seg][1]) * t,
        ]);
    }
    return out;
}

// ─── Main ─────────────────────────────────────────────────────────────────────

const N = 64; // points per normalised path
const VB = 1; // normalised viewBox size (0 0 1 1)

const outLines: string[] = [
    `// AUTO-GENERATED by scripts/normalize-shapes.ts — do not edit manually`,
    `// Run: npx tsx scripts/normalize-shapes.ts`,
    `//`,
    `// Every shape is stored as a ${N}-point polyline normalised to a 0 0 1 1 viewBox.`,
    `// The browser interpolates between paths natively via CSS transition on <path d>.`,
    ``,
    `import { ShapeType } from "./shape.style";`,
    ``,
    `export interface NormalizedShape {`,
    `    /** Normalised SVG path — ${N} L commands in a 0 0 1 1 viewBox. */`,
    `    d: string;`,
    `    /** Original aspect ratio (vbW / vbH) — use to size the SVG element. */`,
    `    aspect: number;`,
    `}`,
    ``,
    `export const SHAPE_DATA: Record<ShapeType, NormalizedShape> = {`,
];

for (const [key, def] of Object.entries(RAW_SHAPES)) {
    const pts = resample(pathToPolyline(def.path, 1 / def.vbW, 1 / def.vbH), N);
    const d = [
        `M${pts[0][0].toFixed(5)} ${pts[0][1].toFixed(5)}`,
        ...pts.slice(1).map((p) => `L${p[0].toFixed(5)} ${p[1].toFixed(5)}`),
        "Z",
    ].join("");

    const enumKey = key.toUpperCase().replace(/-/g, "_");
    outLines.push(
        `    [ShapeType.${enumKey}]: { aspect: ${(def.vbW / def.vbH).toFixed(6)}, d: "${d}" },`,
    );
}

outLines.push(`};`);
outLines.push(``);

const outPath = path.resolve(
    __dirname,
    "../libs/components/shape/shape.data.ts",
);
fs.writeFileSync(outPath, outLines.join("\n"), "utf-8");
console.log(`✓ Written ${Object.keys(RAW_SHAPES).length} shapes → ${outPath}`);
